#include <stdio.h>
#define MOD 1000000007
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        long long ans = 0;
        for (int L = 1; L <= N; L++) {
            for (int R = L; R <= N; R++) {
                int cnt[10] = {0};
                for (int i = L; i <= R; i++) {
                    int num = i;
                    while (num > 0) {
                        cnt[num % 10]++;
                        num /= 10;
                    }
                }
                int distinct = 0;
                for (int i = 0; i < 10; i++) {
                    if (cnt[i] > 0) distinct++;
                }
                ans = (ans + distinct) % MOD;
            }
        }
        printf("%lld\n", ans);
    }
    return 0;
}

