public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            long ans = 0;
            final int MOD = 1000000007;
            for (int L = 1; L <= N; L++) {
                for (int R = L; R <= N; R++) {
                    int[] cnt = new int[10];
                    for (int i = L; i <= R; i++) {
                        int num = i;
                        while (num > 0) {
                            cnt[num % 10]++;
                            num /= 10;
                        }
                    }
                    int distinct = 0;
                    for (int i = 0; i < 10; i++) {
                        if (cnt[i] > 0) distinct++;
                    }
                    ans = (ans + distinct) % MOD;
                }
            }
            System.out.println(ans);
        }
    }
